section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "faion://python-typing/output.schema.json",
  "type": "object",
  "required": ["module", "python_version_floor", "mypy_strict", "errors", "any_count", "ignores"],
  "additionalProperties": false,
  "properties": {
    "module": {"type": "string", "description": "Dotted path of annotated module"},
    "python_version_floor": {"type": "string", "pattern": "^3\\.(1[0-9]|[2-9][0-9])$"},
    "mypy_strict": {"type": "boolean", "const": true},
    "errors": {
      "type": "object",
      "required": ["before", "after"],
      "properties": {
        "before": {"type": "integer", "minimum": 0},
        "after":  {"type": "integer", "minimum": 0, "maximum": 0}
      }
    },
    "any_count": {
      "type": "object",
      "required": ["before", "after"],
      "properties": {
        "before": {"type": "integer", "minimum": 0},
        "after":  {"type": "integer", "minimum": 0}
      }
    },
    "ignores": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["file", "line", "code", "justification"],
        "properties": {
          "file": {"type": "string"},
          "line": {"type": "integer", "minimum": 1},
          "code": {"type": "string", "pattern": "^[a-z-]+$"},
          "justification": {"type": "string", "minLength": 5}
        }
      }
    }
  }
}

example.code:
{
  "module": "myapp.services.billing",
  "python_version_floor": "3.12",
  "mypy_strict": true,
  "errors": {"before": 42, "after": 0},
  "any_count": {"before": 11, "after": 1},
  "ignores": [
    {
      "file": "myapp/services/billing.py",
      "line": 87,
      "code": "no-any-return",
      "justification": "django-stubs lacks typing for Manager.raw() — wrapped in QuerySet[Invoice] one level above."
    }
  ]
}
